import java.util.*;

public class ListVariants {

    public static void main(String[] args) {
        // ArrayList: backed by array — O(1) get, O(n) add/remove middle
        List<String> arrayList = new ArrayList<>();
        arrayList.add("A"); arrayList.add("B"); arrayList.add("C");
        arrayList.add(1, "X");          // insert at index 1 — shifts right: O(n)
        System.out.println(arrayList);  // [A, X, B, C]
        System.out.println(arrayList.get(2)); // B — O(1) random access

        // LinkedList: doubly-linked — O(1) add/remove at ends, O(n) get by index
        LinkedList<String> linked = new LinkedList<>();
        linked.addFirst("First");  // O(1)
        linked.addLast("Last");    // O(1)
        linked.add("Middle");
        System.out.println(linked); // [First, Middle, Last] — insertion order

        // LinkedList as Deque
        linked.push("Stack-top"); // adds to front
        System.out.println(linked.pop()); // Stack-top

        // Performance comparison for head insertions (10k ops)
        long t1 = System.nanoTime();
        List<Integer> al = new ArrayList<>();
        for (int i = 0; i < 10_000; i++) al.add(0, i); // O(n) each — O(n²) total
        long alTime = System.nanoTime() - t1;

        long t2 = System.nanoTime();
        LinkedList<Integer> ll = new LinkedList<>();
        for (int i = 0; i < 10_000; i++) ll.addFirst(i); // O(1) each — O(n) total
        long llTime = System.nanoTime() - t2;

        System.out.printf("ArrayList head-insert: %dms%n", alTime / 1_000_000);
        System.out.printf("LinkedList head-insert: %dms%n", llTime / 1_000_000);
        // LinkedList is dramatically faster for front insertions
    }
}

import java.util.*;

public class SetVariants {

    public static void main(String[] args) {
        // HashSet: O(1) add/contains/remove, NO ordering guarantee
        Set<String> hash = new HashSet<>(List.of("banana", "apple", "cherry", "apple"));
        System.out.println(hash); // {banana, cherry, apple} — no duplicate, arbitrary order
        System.out.println(hash.contains("apple")); // true — O(1)

        // LinkedHashSet: insertion order preserved, O(1) operations
        Set<String> linked = new LinkedHashSet<>(List.of("banana", "apple", "cherry", "apple"));
        System.out.println(linked); // [banana, apple, cherry] — insertion order, no duplicate

        // TreeSet: natural sorted order, O(log n) operations
        Set<String> tree = new TreeSet<>(List.of("banana", "apple", "cherry"));
        System.out.println(tree);  // [apple, banana, cherry] — sorted

        // TreeSet navigation methods
        TreeSet<Integer> nums = new TreeSet<>(List.of(1, 3, 5, 7, 9));
        System.out.println(nums.floor(6));   // 5 — largest <= 6
        System.out.println(nums.ceiling(6)); // 7 — smallest >= 6
        System.out.println(nums.headSet(5)); // [1, 3] — elements < 5
        System.out.println(nums.tailSet(5)); // [5, 7, 9] — elements >= 5
        System.out.println(nums.subSet(3, 8)); // [3, 5, 7] — 3 <= x < 8

        // Deduplication use case
        List<String> withDupes = List.of("a", "b", "a", "c", "b", "d");
        Set<String> unique = new LinkedHashSet<>(withDupes); // preserves order + deduplicates
        System.out.println(unique); // [a, b, c, d]
    }
}

import java.util.*;

public class MapVariants {

    public static void main(String[] args) {
        // HashMap: O(1) avg, no order
        Map<String, Integer> freq = new HashMap<>();
        String[] words = {"cat", "dog", "cat", "bird", "dog", "cat"};
        for (String w : words)
            freq.merge(w, 1, Integer::sum); // elegant frequency count
        System.out.println(freq); // {cat=3, dog=2, bird=1} — arbitrary order

        // LinkedHashMap: insertion-order iteration — great for LRU cache base
        Map<String, Integer> ordered = new LinkedHashMap<>();
        ordered.put("one", 1); ordered.put("two", 2); ordered.put("three", 3);
        System.out.println(ordered); // {one=1, two=2, three=3} — insertion order

        // Access-order LinkedHashMap for LRU
        Map<String, String> lru = new LinkedHashMap<>(16, 0.75f, true) { // accessOrder=true
            @Override protected boolean removeEldestEntry(Map.Entry<String,String> e) {
                return size() > 3;
            }
        };
        lru.put("a", "1"); lru.put("b", "2"); lru.put("c", "3");
        lru.get("a"); // access 'a' — moves to tail (most recently used)
        lru.put("d", "4"); // evicts LRU = 'b'
        System.out.println(lru.keySet()); // [c, a, d] — b evicted

        // TreeMap: sorted by key, navigation operations
        TreeMap<Integer, String> events = new TreeMap<>();
        events.put(1000, "Start"); events.put(3000, "Pause"); events.put(2000, "Middle");
        System.out.println(events);               // {1000=Start, 2000=Middle, 3000=Pause}
        System.out.println(events.floorKey(2500)); // 2000 — largest key <= 2500
        System.out.println(events.headMap(2000));  // {1000=Start} — keys < 2000
    }
}

import java.util.*;

public class QueueAndDeque {

    public static void main(String[] args) {
        // ArrayDeque as FIFO Queue
        Deque<String> queue = new ArrayDeque<>();
        queue.offer("Task1"); queue.offer("Task2"); queue.offer("Task3");
        System.out.println(queue.poll());  // Task1 — FIFO
        System.out.println(queue.peek());  // Task2 — look without removing

        // ArrayDeque as LIFO Stack (preferred over java.util.Stack)
        Deque<Integer> stack = new ArrayDeque<>();
        stack.push(10); stack.push(20); stack.push(30);
        System.out.println(stack.pop());  // 30 — LIFO
        System.out.println(stack.peek()); // 20

        // PriorityQueue: min-heap by default
        PriorityQueue<Integer> minHeap = new PriorityQueue<>();
        minHeap.offer(5); minHeap.offer(1); minHeap.offer(3);
        System.out.println(minHeap.poll()); // 1 — minimum first
        System.out.println(minHeap.poll()); // 3

        // PriorityQueue with custom Comparator: max-heap
        PriorityQueue<Integer> maxHeap = new PriorityQueue<>(Comparator.reverseOrder());
        maxHeap.offer(5); maxHeap.offer(1); maxHeap.offer(3);
        System.out.println(maxHeap.poll()); // 5 — maximum first

        // PriorityQueue with objects: sort by priority field
        record Task(String name, int priority) {}
        PriorityQueue<Task> tasks = new PriorityQueue<>(
            Comparator.comparingInt(t -> -t.priority()) // higher priority number = served first
        );
        tasks.offer(new Task("Low", 1));
        tasks.offer(new Task("High", 10));
        tasks.offer(new Task("Med", 5));
        while (!tasks.isEmpty()) System.out.println(tasks.poll().name());
        // High, Med, Low
    }
}

import java.util.*;

public class CollectionsUtil {

    public static void main(String[] args) {
        List<Integer> nums = new ArrayList<>(List.of(3, 1, 4, 1, 5, 9, 2, 6, 5, 3));

        // Sorting
        Collections.sort(nums);
        System.out.println(nums); // [1, 1, 2, 3, 3, 4, 5, 5, 6, 9]

        // Binary search (list must be sorted)
        int idx = Collections.binarySearch(nums, 5);
        System.out.println("5 found at index: " + idx); // 6 or 7 (any valid index)

        // Frequency
        System.out.println("freq of 3: " + Collections.frequency(nums, 3)); // 2

        // Min and Max
        System.out.println("min: " + Collections.min(nums)); // 1
        System.out.println("max: " + Collections.max(nums)); // 9

        // Shuffle and reverse
        List<Integer> copy = new ArrayList<>(nums);
        Collections.shuffle(copy, new Random(42));
        System.out.println("shuffled: " + copy);
        Collections.reverse(copy);

        // Unmodifiable wrapper — read-only view
        List<String> mutable = new ArrayList<>(List.of("a", "b", "c"));
        List<String> readOnly = Collections.unmodifiableList(mutable);
        try { readOnly.add("d"); }
        catch (UnsupportedOperationException e) { System.out.println("Cannot modify read-only list"); }

        // Synchronized wrapper for thread safety (prefer ConcurrentHashMap for maps)
        List<String> synced = Collections.synchronizedList(new ArrayList<>());

        // nCopies — fill a list with n copies of an object
        List<String> zeros = Collections.nCopies(5, "0");
        System.out.println(zeros); // [0, 0, 0, 0, 0]

        // disjoint — checks if two collections share no elements
        System.out.println(Collections.disjoint(Set.of(1,2,3), Set.of(4,5,6))); // true
        System.out.println(Collections.disjoint(Set.of(1,2,3), Set.of(3,4,5))); // false
    }
}

