import java.util.*;

public class Q1 {
    public static Map<String, Integer> frequency(String[] words) {
        Map<String, Integer> map = new HashMap<>();
        for (String w : words) map.merge(w, 1, Integer::sum);
        return map;
    }
    public static String mostFrequent(String[] words) {
        Map<String, Integer> map = frequency(words);
        return Collections.max(map.entrySet(), Map.Entry.comparingByValue()).getKey();
    }
    public static void main(String[] args) {
        String[] w = {"cat","dog","cat","bird","dog","cat"};
        System.out.println(frequency(w)); // {cat=3, dog=2, bird=1}
        System.out.println(mostFrequent(w)); // cat
    }
}

