import java.util.*;

public class Q7 {
    public static int[] topKFrequent(int[] nums, int k) {
        // Step 1: frequency map
        Map<Integer, Integer> freq = new HashMap<>();
        for (int n : nums) freq.merge(n, 1, Integer::sum);

        // Step 2: min-heap ordered by frequency, size <= k
        PriorityQueue<Integer> heap = new PriorityQueue<>(
            Comparator.comparingInt(freq::get)
        );
        for (int num : freq.keySet()) {
            heap.offer(num);
            if (heap.size() > k) heap.poll(); // evict least frequent
        }

        // Step 3: extract result
        int[] result = new int[k];
        for (int i = k - 1; i >= 0; i--) result[i] = heap.poll();
        return result;
    }
    public static void main(String[] args) {
        System.out.println(Arrays.toString(topKFrequent(new int[]{1,1,1,2,2,3}, 2))); // [1, 2]
    }
}

