import java.util.*;

public class Q11 {
    record Employee(String name, String department) {}

    public static Map<String, List<String>> groupByDepartment(List<Employee> employees) {
        Map<String, List<String>> map = new TreeMap<>();
        for (Employee e : employees)
            map.computeIfAbsent(e.department(), k -> new ArrayList<>()).add(e.name());
        map.values().forEach(Collections::sort);
        return map;
    }
    public static void main(String[] args) {
        List<Employee> emps = List.of(
            new Employee("Alice","Eng"), new Employee("Bob","HR"),
            new Employee("Carol","Eng"), new Employee("Dave","HR"),
            new Employee("Eve","Eng")
        );
        groupByDepartment(emps).forEach((dept, names) ->
            System.out.println(dept + ": " + names));
        // Eng: [Alice, Carol, Eve]
        // HR: [Bob, Dave]
    }
}

