import java.util.*;

public class Q15 {
    static class MedianFinder {
        PriorityQueue<Integer> lower = new PriorityQueue<>(Comparator.reverseOrder()); // max-heap
        PriorityQueue<Integer> upper = new PriorityQueue<>(); // min-heap

        public void addNum(int num) {
            lower.offer(num); // add to lower first
            upper.offer(lower.poll()); // push max of lower to upper
            if (upper.size() > lower.size()) // keep lower >= upper size
                lower.offer(upper.poll());
        }

        public double findMedian() {
            if (lower.size() > upper.size()) return lower.peek();
            return (lower.peek() + upper.peek()) / 2.0;
        }
    }

    public static void main(String[] args) {
        MedianFinder mf = new MedianFinder();
        mf.addNum(1); mf.addNum(2);
        System.out.println(mf.findMedian()); // 1.5
        mf.addNum(3);
        System.out.println(mf.findMedian()); // 2.0
        mf.addNum(4);
        System.out.println(mf.findMedian()); // 2.5
    }
}

