import java.util.*;

public class Q16 {
    static class LFUCache {
        int capacity, minFreq;
        Map<Integer, Integer> values  = new HashMap<>();
        Map<Integer, Integer> counts  = new HashMap<>();
        Map<Integer, LinkedHashSet<Integer>> freqToKeys = new HashMap<>();

        LFUCache(int capacity) { this.capacity = capacity; }

        public int get(int key) {
            if (!values.containsKey(key)) return -1;
            increment(key);
            return values.get(key);
        }

        public void put(int key, int value) {
            if (capacity <= 0) return;
            if (values.containsKey(key)) { values.put(key, value); increment(key); return; }
            if (values.size() == capacity) evict();
            values.put(key, value);
            counts.put(key, 1);
            freqToKeys.computeIfAbsent(1, k -> new LinkedHashSet<>()).add(key);
            minFreq = 1;
        }

        private void increment(int key) {
            int freq = counts.get(key);
            counts.put(key, freq + 1);
            freqToKeys.get(freq).remove(key);
            if (freqToKeys.get(freq).isEmpty() && freq == minFreq) minFreq++;
            freqToKeys.computeIfAbsent(freq + 1, k -> new LinkedHashSet<>()).add(key);
        }

        private void evict() {
            LinkedHashSet<Integer> keys = freqToKeys.get(minFreq);
            int lru = keys.iterator().next(); // oldest at front
            keys.remove(lru);
            values.remove(lru);
            counts.remove(lru);
        }
    }

    public static void main(String[] args) {
        LFUCache lfu = new LFUCache(2);
        lfu.put(1, 1); lfu.put(2, 2);
        System.out.println(lfu.get(1)); // 1
        lfu.put(3, 3);
        System.out.println(lfu.get(2)); // -1
        System.out.println(lfu.get(3)); // 3
    }
}

