import java.util.*;

public class Q18 {
    static class Twitter {
        private int time = 0;
        private Map<Integer, List<int[]>> tweets = new HashMap<>();
        private Map<Integer, Set<Integer>> follows = new HashMap<>();

        public void postTweet(int userId, int tweetId) {
            tweets.computeIfAbsent(userId, k -> new ArrayList<>()).add(new int[]{time++, tweetId});
        }

        public List<Integer> getNewsFeed(int userId) {
            // max-heap by timestamp: [timestamp, tweetId, userIdx, listIndex]
            PriorityQueue<int[]> heap = new PriorityQueue<>((a,b) -> b[0]-a[0]);

            Set<Integer> users = new HashSet<>();
            users.add(userId);
            if (follows.containsKey(userId)) users.addAll(follows.get(userId));

            for (int uid : users) {
                List<int[]> list = tweets.getOrDefault(uid, List.of());
                if (!list.isEmpty()) {
                    int idx = list.size() - 1;
                    int[] last = list.get(idx);
                    heap.offer(new int[]{last[0], last[1], uid, idx - 1});
                }
            }

            List<Integer> feed = new ArrayList<>();
            while (!heap.isEmpty() && feed.size() < 10) {
                int[] top = heap.poll();
                feed.add(top[1]);
                if (top[3] >= 0) {
                    List<int[]> list = tweets.get(top[2]);
                    int[] next = list.get(top[3]);
                    heap.offer(new int[]{next[0], next[1], top[2], top[3]-1});
                }
            }
            return feed;
        }

        public void follow(int followerId, int followeeId) {
            follows.computeIfAbsent(followerId, k -> new HashSet<>()).add(followeeId);
        }

        public void unfollow(int followerId, int followeeId) {
            if (follows.containsKey(followerId)) follows.get(followerId).remove(followeeId);
        }
    }

    public static void main(String[] args) {
        Twitter t = new Twitter();
        t.postTweet(1, 5); t.postTweet(1, 3); t.postTweet(2, 10);
        t.follow(1, 2);
