import java.util.*;

public class Q19 {
    static class TreeNode {
        int val; TreeNode left, right;
        TreeNode(int v) { val = v; }
    }

    public static String serialize(TreeNode root) {
        List<String> result = new ArrayList<>();
        serHelper(root, result);
        return String.join(",", result);
    }

    static void serHelper(TreeNode node, List<String> result) {
        if (node == null) return;
        result.add(String.valueOf(node.val));
        serHelper(node.left, result);
        serHelper(node.right, result);
    }

    public static TreeNode deserialize(String data) {
        if (data.isEmpty()) return null;
        Queue<Integer> queue = new ArrayDeque<>();
        for (String s : data.split(",")) queue.offer(Integer.parseInt(s));
        return desHelper(queue, Integer.MIN_VALUE, Integer.MAX_VALUE);
    }

    static TreeNode desHelper(Queue<Integer> q, int min, int max) {
        if (q.isEmpty() || q.peek() < min || q.peek() > max) return null;
        int val = q.poll();
        TreeNode node = new TreeNode(val);
        node.left  = desHelper(q, min, val);
        node.right = desHelper(q, val, max);
        return node;
    }

    static void inorder(TreeNode root, List<Integer> r) {
        if (root == null) return;
        inorder(root.left, r); r.add(root.val); inorder(root.right, r);
    }

    public static void main(String[] args) {
        TreeNode root = new TreeNode(5);
        root.left = new TreeNode(3); root.right = new TreeNode(7);
        root.left.left = new TreeNode(1); root.left.right = new TreeNode(4);
        String s = serialize(root);
        System.out.println(s); // 5,3,1,4,7
        TreeNode rebuilt = deserialize(s);
        List<Integer> vals = new ArrayList<>();
        inorder(rebuilt, vals);
        System.out.println(vals); // [1, 3, 4, 5, 7]
    }
}

